    /// <summary>Attribute identifiers.</summary>
    public static class Attributes
    {
        /// <summary>SupportedAreas (0x0000).</summary>
        public const uint SupportedAreas = 0x0000;
        /// <summary>SupportedMaps (0x0001).</summary>
        public const uint SupportedMaps = 0x0001;
        /// <summary>SelectedAreas (0x0002).</summary>
        public const uint SelectedAreas = 0x0002;
        /// <summary>CurrentArea (0x0003).</summary>
        public const uint CurrentArea = 0x0003;
        /// <summary>EstimatedEndTime (0x0004).</summary>
        public const uint EstimatedEndTime = 0x0004;
        /// <summary>Progress (0x0005).</summary>
        public const uint Progress = 0x0005;
    }

    /// <summary>Command identifiers.</summary>
    public static class Commands
    {
        /// <summary>SelectAreas (0x0000).</summary>
        public const uint SelectAreas = 0x0000;
        /// <summary>SkipArea (0x0002).</summary>
        public const uint SkipArea = 0x0002;
    }

    // Async command methods

    /// <summary>Send SelectAreas command (0x0000).</summary>
    public Task<InvokeResponse> SelectAreasAsync(
        uint[] newAreas,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0000, tlv => { if (newAreas != null) { tlv.AddArray(0); foreach (var item in newAreas) { tlv.AddUInt32(item); } tlv.EndContainer(); } }, ct);

    /// <summary>Send SkipArea command (0x0002).</summary>
    public Task<InvokeResponse> SkipAreaAsync(
        uint skippedArea,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0002, tlv => { tlv.AddUInt32(0, skippedArea); }, ct);

    // Attribute readers

    /// <summary>Read SupportedAreas attribute (0x0000).</summary>
    public Task<AreaStruct[]?> ReadSupportedAreasAsync(CancellationToken ct = default)
        => ReadRefAttributeAsync<AreaStruct[]>(0x0000, ct);

    /// <summary>Read SupportedMaps attribute (0x0001).</summary>
    public Task<MapStruct[]?> ReadSupportedMapsAsync(CancellationToken ct = default)
        => ReadRefAttributeAsync<MapStruct[]>(0x0001, ct);

    /// <summary>Read SelectedAreas attribute (0x0002).</summary>
    public Task<uint[]?> ReadSelectedAreasAsync(CancellationToken ct = default)
        => ReadRefAttributeAsync<uint[]>(0x0002, ct);

    /// <summary>Read CurrentArea attribute (0x0003).</summary>
    public Task<uint?> ReadCurrentAreaAsync(CancellationToken ct = default)
        => ReadNullableAttributeAsync<uint>(0x0003, ct);

    /// <summary>Read EstimatedEndTime attribute (0x0004).</summary>
    public Task<uint?> ReadEstimatedEndTimeAsync(CancellationToken ct = default)
        => ReadNullableAttributeAsync<uint>(0x0004, ct);

    /// <summary>Read Progress attribute (0x0005).</summary>
    public Task<ProgressStruct[]?> ReadProgressAsync(CancellationToken ct = default)
        => ReadRefAttributeAsync<ProgressStruct[]>(0x0005, ct);
}
